const PERSONALITY_DESCRIPTIONS_PT: Record<string, string> = {
  conservador: "Presidente conservador e criterioso, prefere estabilidade ao risco. Dá suporte ao técnico enquanto vê progressão e cobra resultados consistentes. Gerencia o clube com prudência financeira e evita decisões impulsivas. Tem paciência com ciclos naturais do futebol, mas cobra comprometimento constante.",
  agressivo: "Presidente exigente e impaciente, espera resultados imediatos dos investimentos. Pode ser impulsivo em momentos de crise e pressiona o técnico constantemente. Tem dificuldade em aceitar sequências negativas e pode tomar decisões abruptas. No entanto, quando as coisas vão bem, celebra generosamente os resultados alcançados.",
  analitico: "Presidente analítico que toma decisões baseadas em dados e indicadores de desempenho. Avalia o trabalho do técnico com critério e objetividade. Dá suporte ao projeto enquanto os números justificam as escolhas táticas. Tem aversão a decisões impulsivas e valoriza planejamento de longo prazo.",
  emocional: "Presidente apaixonado que vive intensamente cada resultado da equipe. Pode ser impulsivo quando as coisas não vão bem, mas é extremamente generoso nos momentos de vitória. Valoriza conexão com os torcedores e espera que o técnico entenda a alma do clube. Tem sentimentos fortes sobre o estilo de jogo e a identidade da equipe.",
  diplomatico: "Presidente diplomático que navega bem entre torcida, jogadores e imprensa. Tem paciência com projetos de longo prazo e valoriza o comprometimento da equipe. Gere conflitos internos com habilidade e raramente entra em confronto público. Cobra resultados, mas entende que o futebol tem ciclos e dá tempo ao técnico para trabalhar.",
  exigente: "Presidente altamente exigente que não aceita mediocridade. Cobra alta performance em todas as competições e tem expectativas proporcionais ao potencial do clube. Analisa cada detalhe e questiona decisões táticas quando os resultados não satisfazem. Leal aos que entregam, mas implacável com quem decepciona.",
};

const PERSONALITY_DESCRIPTIONS_EN: Record<string, string> = {
  conservador: "A cautious and methodical president who values stability over risk. Supports the manager while progress is evident and demands consistent results. Handles the club with financial prudence and avoids impulsive decisions. Patient with the natural cycles of football but always expects commitment.",
  agressivo: "A demanding and impatient president who expects immediate returns on investment. Can be impulsive in crisis moments and pressures the manager constantly. Struggles to accept losing runs and may make sudden decisions. However, when things go well, celebrates achievements generously.",
  analitico: "An analytical president who bases decisions on data and performance metrics. Evaluates the manager's work with objectivity and precision. Backs the project as long as the numbers justify the tactical choices. Dislikes impulsive decisions and values long-term planning.",
  emocional: "A passionate president who experiences every result deeply. Can be impulsive when things aren't going well but is extremely generous in victory. Values the connection with supporters and expects the manager to understand the club's soul. Has strong feelings about playing style and team identity.",
  diplomatico: "A diplomatic president who handles supporters, players and the press with skill. Patient with long-term projects and values team commitment. Manages internal conflicts smoothly and rarely clashes publicly. Demands results but understands that football runs in cycles and gives the manager time to work.",
  exigente: "A highly demanding president who does not accept mediocrity. Expects top performance in every competition with expectations matching the club's potential. Scrutinises every detail and questions tactical decisions when results disappoint. Loyal to those who deliver, ruthless with those who let the club down.",
};

function getRandomItem<T>(arr: T[], seed: number): T {
  return arr[Math.abs(seed) % arr.length];
}

const PERSONALITIES: PersonalityStyle[] = ["conservador", "diplomatico", "analitico", "emocional", "exigente", "agressivo"];

export function getClubPresident(clubId: number): ClubPresidentData | null {
  return CLUB_PRESIDENTS[clubId] ?? null;
}

export function buildFallbackPresident(
  clubId: number,
  clubCountry?: string,
  personality?: string,
): ClubPresidentData {
  const pers = (personality as PersonalityStyle | undefined) ?? PERSONALITIES[Math.abs(clubId) % PERSONALITIES.length];
  const patience = PATIENCE_BY_PERSONALITY[pers] ?? 60;
  const countryNames = COUNTRY_NAMES[clubCountry ?? ""] ?? COUNTRY_NAMES.default;
  const name = getRandomItem(countryNames, clubId);
  const description = PERSONALITY_DESCRIPTIONS_PT[pers] ?? PERSONALITY_DESCRIPTIONS_PT.diplomatico;
  const descriptionEn = PERSONALITY_DESCRIPTIONS_EN[pers] ?? PERSONALITY_DESCRIPTIONS_EN.diplomatico;
  return { name, personality: pers, patience, description, descriptionEn };
}

export function getPresidentDescription(
  data: ClubPresidentData,
  lang: "pt" | "en",
): string {
  if (lang === "en") {
    return data.descriptionEn ?? PERSONALITY_DESCRIPTIONS_EN[data.personality] ?? PERSONALITY_DESCRIPTIONS_EN.diplomatico;
  }
  return data.description;
}
